                 xtol=1e-5):
    for _ in range(max_iter):
        f, J = fun_with_jac(x)
        grad = mu * J.T.mv(f)
        grad.add_(d - x - b, alpha=-lambd)
        JtJ = mu * J.T.mm(J)
        JtJ.diagonal().add_(lambd)
        try:
            p = torch.cholesky_solve(grad.unsqueeze(1),
                                     torch.linalg.cholesky(JtJ)).squeeze(1)
